import{_ as o,o as t,c as a,a2 as n}from"./chunks/framework.B8zgMDLd.js";const p=JSON.parse('{"title":"Configure AI Models","description":"","frontmatter":{},"headers":[],"relativePath":"guides/configure-ai-models.md","filePath":"guides/configure-ai-models.md"}'),r={name:"guides/configure-ai-models.md"};function i(l,e,s,d,c,h){return t(),a("div",null,[...e[0]||(e[0]=[n('<h1 id="configure-ai-models" tabindex="-1">Configure AI Models <a class="header-anchor" href="#configure-ai-models" aria-label="Permalink to &quot;Configure AI Models&quot;">​</a></h1><p>Use model providers when you want chat over note context without giving an agent vault-write tools.</p><h2 id="local-models" tabindex="-1">Local Models <a class="header-anchor" href="#local-models" aria-label="Permalink to &quot;Local Models&quot;">​</a></h2><p>Local model targets are for tools such as Ollama and LM Studio. They usually need a base URL and model ID, and they usually do not need an API key.</p><h2 id="api-models" tabindex="-1">API Models <a class="header-anchor" href="#api-models" aria-label="Permalink to &quot;API Models&quot;">​</a></h2><p>API model targets are for hosted providers such as OpenAI, Anthropic, Gemini, OpenRouter, or another OpenAI-compatible endpoint.</p><p>Tolaria does not store provider API keys in vault settings. Choose one of the supported key paths:</p><ul><li>Save the key locally on this device.</li><li>Read the key from an environment variable.</li><li>Use no key for local providers that do not require one.</li></ul><h2 id="test-the-connection" tabindex="-1">Test The Connection <a class="header-anchor" href="#test-the-connection" aria-label="Permalink to &quot;Test The Connection&quot;">​</a></h2><p>After adding a provider, use the test action in Settings. A successful test means Tolaria reached the endpoint and the model replied.</p><h2 id="select-the-target" tabindex="-1">Select The Target <a class="header-anchor" href="#select-the-target" aria-label="Permalink to &quot;Select The Target&quot;">​</a></h2><p>Once configured, choose the model from the AI target selector or set it as the default AI target in Settings.</p>',12)])])}const m=o(r,[["render",i]]);export{p as __pageData,m as default};
